(()=>{const $=(root,sel)=>root.querySelector(sel);const $$=(root,sel)=>[...root.querySelectorAll(sel)];const ext={'image/jpeg':'jpg','image/png':'png','image/webp':'webp'};function setStatus(root,msg){const el=$(root,'[data-status]');if(el)el.textContent=msg;}function formatBytes(n){if(!Number.isFinite(n))return'0 B';const u=['B','KB','MB','GB'];let i=0;while(n>=1024&&i<u.length-1){n/=1024;i++;}return`${n.toFixed(i?1:0)} ${u[i]}`;}function readImage(file){return new Promise((resolve,reject)=>{const url=URL.createObjectURL(file);const img=new Image();img.onload=()=>resolve({img,url});img.onerror=reject;img.src=url;});}function canvasToBlob(canvas,type,quality){return new Promise(resolve=>canvas.toBlob(resolve,type,quality));}function drawImageToCanvas(img,w=img.naturalWidth,h=img.naturalHeight,bg=null){const c=document.createElement('canvas');c.width=Math.max(1,Math.round(w));c.height=Math.max(1,Math.round(h));const ctx=c.getContext('2d');if(bg){ctx.fillStyle=bg;ctx.fillRect(0,0,c.width,c.height);}ctx.drawImage(img,0,0,c.width,c.height);return c;}async function outputBlob(root,canvas,type,quality,file){const blob=await canvasToBlob(canvas,type,quality);if(!blob){setStatus(root,'This browser could not create that output format. Try JPG or PNG.');return;}const url=URL.createObjectURL(blob);const img=$(root,'[data-result-preview]');img.src=url;img.hidden=false;const dl=$(root,'[data-download]');dl.href=url;dl.download=`pawstool-${root.dataset.toolSlug || 'image'}.${ext[type] || 'png'}`;dl.hidden=false;setStatus(root,`Original: ${formatBytes(file.size)} · Result: ${formatBytes(blob.size)} · Saved ${(100-(blob.size/file.size*100)).toFixed(1)}%`);}async function loadSelected(root){const input=$(root,'[data-image-file]');const file=input?.files?.[0];if(!file)throw new Error('Choose an image first.');const data=await readImage(file);const prev=$(root,'[data-original-preview]');prev.src=data.url;prev.hidden=false;return{file,...data};}function selectedFormat(root,fallback,file){const val=$(root,'[data-format]')?.value;return val&&val!=='auto'?val:(fallback==='auto'?(file.type||'image/png'):fallback);}async function run(root){try{const mode=root.dataset.toolMode;const fallback=root.dataset.outputFormat||'image/png';const{file,img}=await loadSelected(root);const q=parseFloat($(root,'[data-quality]')?.value||'0.92');const bg=$(root,'[data-bg]')?.value||null;if(mode==='base64'){const text=await file.text().catch(()=>null);const dataUrl=await new Promise((resolve,reject)=>{const r=new FileReader();r.onload=()=>resolve(r.result);r.onerror=reject;r.readAsDataURL(file);});const out=$(root,'[data-text-output]');out.hidden=false;out.value=dataUrl;$(root,'[data-copy]').hidden=false;setStatus(root,`Encoded ${formatBytes(file.size)} into ${dataUrl.length.toLocaleString()} characters.`);return;}let canvas,type=selectedFormat(root,fallback,file),quality=q;if(mode==='resize'){let w=parseInt($(root,'[data-width]')?.value||img.naturalWidth,10);let h=parseInt($(root,'[data-height]')?.value||img.naturalHeight,10);if($(root,'[data-keep-ratio]')?.checked){if($(root,'[data-width]')?.value&&!$(root,'[data-height]')?.value)h=Math.round(w*img.naturalHeight/img.naturalWidth);if($(root,'[data-height]')?.value&&!$(root,'[data-width]')?.value)w=Math.round(h*img.naturalWidth/img.naturalHeight);}canvas=drawImageToCanvas(img,w,h,type==='image/jpeg'?'#fff':null);}else if(mode==='compress'){const maxW=parseInt($(root,'[data-width]')?.value||img.naturalWidth,10);const ratio=Math.min(1,maxW/img.naturalWidth);canvas=drawImageToCanvas(img,img.naturalWidth*ratio,img.naturalHeight*ratio,type==='image/jpeg'?'#fff':null);}else if(mode==='crop'){const x=parseInt($(root,'[data-x]')?.value||0,10),y=parseInt($(root,'[data-y]')?.value||0,10);const w=parseInt($(root,'[data-width]')?.value||(img.naturalWidth-x),10),h=parseInt($(root,'[data-height]')?.value||(img.naturalHeight-y),10);canvas=document.createElement('canvas');canvas.width=Math.max(1,w);canvas.height=Math.max(1,h);canvas.getContext('2d').drawImage(img,x,y,w,h,0,0,w,h);type=file.type||'image/png';}else if(mode==='rotate'){const deg=parseInt($(root,'[data-degrees]')?.value||90,10);const rad=deg*Math.PI/180;canvas=document.createElement('canvas');const swap=deg%180!==0;canvas.width=swap?img.naturalHeight:img.naturalWidth;canvas.height=swap?img.naturalWidth:img.naturalHeight;const ctx=canvas.getContext('2d');ctx.translate(canvas.width/2,canvas.height/2);ctx.rotate(rad);ctx.drawImage(img,-img.naturalWidth/2,-img.naturalHeight/2);type=file.type||'image/png';}else if(mode==='flip'){const dir=$(root,'[data-direction]')?.value||'horizontal';canvas=document.createElement('canvas');canvas.width=img.naturalWidth;canvas.height=img.naturalHeight;const ctx=canvas.getContext('2d');if(dir==='horizontal'){ctx.translate(canvas.width,0);ctx.scale(-1,1);}else{ctx.translate(0,canvas.height);ctx.scale(1,-1);}ctx.drawImage(img,0,0);type=file.type||'image/png';}else{canvas=drawImageToCanvas(img,img.naturalWidth,img.naturalHeight,(mode==='convert-bg'||type==='image/jpeg')?bg||'#fff':null);}await outputBlob(root,canvas,type,quality,file);}catch(err){setStatus(root,err.message||String(err));}}document.addEventListener('input',e=>{if(e.target.matches('[data-quality]')){const label=e.target.closest('.tool-shell')?.querySelector('[data-quality-label]');if(label)label.textContent=`${Math.round(e.target.value*100)}%`;}});document.addEventListener('click',e=>{const root=e.target.closest('.tool-shell');if(!root)return;if(e.target.matches('[data-action]'))run(root);if(e.target.matches('[data-clear]')){$$(root,'input').forEach(i=>{if(i.type==='file')i.value='';});$$(root,'img').forEach(i=>{i.removeAttribute('src');i.hidden=true;});const out=$(root,'[data-text-output]');if(out){out.value='';out.hidden=true;}$(root,'[data-download]').hidden=true;$(root,'[data-copy]').hidden=true;setStatus(root,'Cleared. Choose another image to begin.');}if(e.target.matches('[data-copy]')){const out=$(root,'[data-text-output]');if(out)navigator.clipboard.writeText(out.value).then(()=>setStatus(root,'Copied output to clipboard.'));}});document.addEventListener('change',async e=>{if(e.target.matches('[data-image-file]')){const root=e.target.closest('.tool-shell');try{const{file,img}=await loadSelected(root);setStatus(root,`Loaded ${file.name} · ${img.naturalWidth}×${img.naturalHeight} · ${formatBytes(file.size)}`);}catch(err){setStatus(root,err.message||String(err));}}});})();